  if (!_queues[user]) {
    _queues[user] = [];
  }
  const queue = _queues[user];
  queue.push(message);
  if (queue.length > _cfg['notifications.maxQueue']) {
    queue.shift();
  }
  emit(EVENTS.MESSAGE_QUEUED, { user, message });
  return STRINGS.MESSAGE_SENT.replace('{user}', user).replace('{message}', message);
}

function list(user) {
  return _queues[user] ? _queues[user].slice() : [];
}

function clear(user) {
  if (_queues[user]) {
    _queues[user] = [];
  }
  return STRINGS.QUEUE_CLEARED.replace('{user}', user);
}

module.exports = { init, send, list, clear };

