'use strict';

const EVENTS = {
  ALERT_RAISED: 'ALERT_RAISED',
  METRIC_RECORDED: 'METRIC_RECORDED',
  USER_ADDED: 'USER_ADDED',
  MESSAGE_QUEUED: 'MESSAGE_QUEUED',
};

const _listeners = {};

function on(event, fn) {
  if (!EVENTS[event]) {
    throw new Error('undeclared event: ' + event);
  }
  if (!_listeners[event]) _listeners[event] = [];
  _listeners[event].push(fn);
}

function emit(event, payload) {
  if (!EVENTS[event]) {
    throw new Error('undeclared event: ' + event);
  }
  const fns = _listeners[event] || [];
  for (const fn of fns) fn(payload);
}

module.exports = { EVENTS, on, emit };

'use strict';

const STRINGS = {
  ALERT_RAISED: 'Alert raised: {level} - {message}',
  METRIC_RECORDED: 'Metric recorded: {name} = {value}',
  USER_ADDED: 'User added: {username}',
  MESSAGE_SENT: 'Message sent to {user}: {message}',
  QUEUE_CLEARED: 'Queue cleared for user: {user}',
  ERR_UNKNOWN_CMD: 'Unknown command: {cmd}',
  ERR_MISSING_ARGS: 'Missing required arguments for: {cmd}',
};

module.exports = { STRINGS };
